/* 1. ENTRANCE ANIMATIONS — CSS */
@keyframes fadeSlideUp {
  from { opacity: 0; transform: translateY(28px); }
  to   { opacity: 1; transform: translateY(0); }
}
.animate-in {
  animation: fadeSlideUp 0.55s cubic-bezier(0.22, 1, 0.36, 1) both;
}
/* Stagger delays */
.animate-in:nth-child(1) { animation-delay: 0s; }
.animate-in:nth-child(2) { animation-delay: 0.08s; }
.animate-in:nth-child(3) { animation-delay: 0.16s; }
.animate-in:nth-child(4) { animation-delay: 0.24s; }

/* Accessibility — ОБОВ'ЯЗКОВО */
@media (prefers-reduced-motion: reduce) {
  .animate-in {
    animation: fadeIn 0.3s ease both;
  }
  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
}

/* 2. BUTTON STATES */
.btn {
  transition: transform 0.18s ease-out,
              box-shadow 0.18s ease-out,
              background-color 0.18s ease;
}
.btn:hover  { transform: translateY(-2px); box-shadow: var(--shadow-md); }
.btn:active { transform: translateY(0px); transition-duration: 0.08s; }

/* 3. CARD HOVER — spring bounce */
.card {
  transition: transform 0.22s cubic-bezier(0.34, 1.56, 0.64, 1),
              box-shadow 0.22s ease;
}
.card:hover { transform: translateY(-6px) scale(1.01); box-shadow: var(--shadow-lg); }

/* Cursor Composer промпт:
@tokens.css @.cursorrules
Додай entrance animation для hero section:
[опиши елементи з тімінгом як у good prompt вище] */

/* IntersectionObserver — production ready */
const observer = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (!entry.isIntersecting) return;
    entry.target.classList.add('is-visible');
    const children = entry.target.querySelectorAll('.stagger-child');
    children.forEach((child, i) => {
      child.style.transitionDelay = `${i * 0.08}s`;
      child.classList.add('is-visible');
    });
    observer.unobserve(entry.target);
  });
}, { threshold: 0.12, rootMargin: '-40px 0px' });

document.querySelectorAll('.scroll-animate').forEach(el => observer.observe(el));

/* CSS */
.scroll-animate {
  opacity: 0;
  transform: translateY(32px);
  transition: opacity 0.55s ease-out,
              transform 0.55s cubic-bezier(0.22, 1, 0.36, 1);
}
.scroll-animate.is-visible { opacity: 1; transform: translateY(0); }
@media (prefers-reduced-motion: reduce) {
  .scroll-animate { opacity: 1; transform: none; }
}

/* CSS Scroll Timeline (Chrome 115+) */
@supports (animation-timeline: scroll()) {
  .parallax-img {
    animation: parallaxMove linear both;
    animation-timeline: scroll();
    animation-range: 0% 100%;
  }
  @keyframes parallaxMove {
    from { transform: translateY(0); }
    to   { transform: translateY(-80px); }
  }
}

/* View Transitions API */
document.querySelectorAll('a[data-transition]').forEach(link => {
  link.addEventListener('click', e => {
    e.preventDefault();
    if (!document.startViewTransition) { window.location = link.href; return; }
    document.startViewTransition(() => { /* update content */ });
  });
});

/* LOTTIE — Web integration */
import lottie from 'lottie-web';

const anim = lottie.loadAnimation({
  container: document.getElementById('lottie-wrap'),
  renderer: 'svg',
  loop: false,
