anim.addEventListener('complete', () => { console.log('done'); });

// Trigger при success
form.addEventListener('submit', async e => {
  e.preventDefault();
  await sendData();
  anim.goToAndPlay(0, true);
});

/* SVG ANIMATED CHECKMARK — Claude prompt:
"Зроби SVG checkmark 24x24 що малюється stroke-dashoffset анімацією.
Duration: 0.6s ease-out. Колір: var(--color-success).
Оптимізовано для React і HTML." */

/* Результат: */
<svg viewBox='0 0 24 24' width='24' height='24'>
  <polyline points='4 12 9 17 20 6'
    stroke='var(--color-success)' stroke-width='2.5'
    fill='none' stroke-linecap='round' stroke-linejoin='round'
    stroke-dasharray='24' stroke-dashoffset='24'
    style='animation: drawCheck 0.6s ease-out 0.1s forwards'/>
</svg>
@keyframes drawCheck {
  to { stroke-dashoffset: 0; }
}

/* REACT NATIVE + Lottie: */
import LottieView from 'lottie-react-native';
<LottieView
  source={require('./animations/loading.json')}
  autoPlay loop style={{ width: 120, height: 120 }}
/>

/* GSAP — встановлення: CDN або npm install gsap */
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
gsap.registerPlugin(ScrollTrigger);

/* HERO ENTRANCE TIMELINE */
const heroTl = gsap.timeline({ delay: 0.2 });
heroTl
  .from('.hero__eyebrow', { opacity:0, y:20, duration:0.5, ease:'power2.out' })
  .from('.hero__title',   { opacity:0, y:30, duration:0.7, ease:'power3.out' }, '<0.1')
  .from('.hero__sub',     { opacity:0, y:20, duration:0.6, ease:'power2.out' }, '<0.15')
  .from('.hero__cta',     { opacity:0, y:16, stagger:0.08, duration:0.5 }, '<0.2')
  .from('.hero__visual',  { opacity:0, scale:0.94, duration:0.9, ease:'power2.out' }, '<0.3');

/* HORIZONTAL SCROLL (pinned section) */
gsap.to('.features__track', {
  x: () => -(document.querySelector('.features__track').scrollWidth - window.innerWidth),
  ease: 'none',
  scrollTrigger: {
    trigger: '.features',
    pin: true,
    scrub: 1,
    start: 'top top',
    end: () => '+=' + document.querySelector('.features__track').scrollWidth
  }
});

/* STAGGER FROM CENTER */
gsap.from('.grid__item', {
  opacity: 0, scale: 0.85,
  duration: 0.5, ease: 'back.out(1.7)',
  stagger: { amount: 0.6, from: 'center' },
  scrollTrigger: { trigger: '.grid', start: 'top 75%' }
});

/* SPLITTEXT (chars) */
// import { SplitText } from 'gsap/SplitText';
const split = new SplitText('.hero__title', { type: 'chars,words' });
gsap.from(split.chars, {
  opacity: 0, y: 40,
  stagger: 0.02, duration: 0.5, ease: 'power3.out'
});

/* FRAMER MOTION — з Claude prompt: */
"Створи Framer Motion animated list component:
- AnimatePresence для add/remove items
- layout animation при reorder
- Initial: opacity 0, x -20
- Animate: opacity 1, x 0
- Exit: opacity 0, x 20
- transition: spring stiffness 300, damping 30"

/* Результат: */
import { motion, AnimatePresence } from 'framer-motion';

const AnimatedList = ({ items }) => (
  <AnimatePresence mode='popLayout'>
    {items.map(item => (
      <motion.li key={item.id}
        layout
        initial={{ opacity: 0, x: -20 }}
        animate={{ opacity: 1, x: 0 }}
        exit={{ opacity: 0, x: 20, transition: { duration: 0.15 } }}
        transition={{ type: 'spring', stiffness: 300, damping: 30 }}
      >
        {item.text}
      </motion.li>
    ))}
  </AnimatePresence>
);

/* FRAMER MOTION — Page transitions: */
const pageVariants = {
  initial: { opacity: 0, y: 16 },
  animate: { opacity: 1, y: 0, transition: { duration: 0.4, ease: [0.22, 1, 0.36, 1] } },
  exit:    { opacity: 0, y: -16, transition: { duration: 0.25 } }
};

